<template><div class="page"><header class="page-head"><div><h1>Calendrier</h1><p>Sorties du {{ periodLabel }}</p></div><div class="actions"><button class="icon-button" title="Mois precedent" @click="move(-1)"><ChevronLeft/></button><button class="secondary" @click="today">Aujourd'hui</button><button class="icon-button" title="Mois suivant" @click="move(1)"><ChevronRight/></button><button class="icon-button" :disabled="loading" title="Actualiser" @click="load"><RefreshCw :class="{spin:loading}"/></button></div></header><div class="toolbar wrap"><input v-model="search" class="search" type="search" placeholder="Filtrer les titres"><select v-model="type"><option value="">Films et series</option><option value="movie">Films</option><option value="episode">Series</option></select><label class="check"><input v-model="tracked" type="checkbox" @change="load"> Suivis uniquement</label></div><p v-if="error" class="notice error-text">{{ error }}</p><section v-for="group in grouped" :key="group.date" :id="'date-' + group.date" class="calendar-day" :class="{ today: group.date === todayStr }"><h2>{{ longDate(group.date) }}<span v-if="group.date === todayStr" class="today-badge"> (Aujourd'hui)</span></h2><div class="calendar-events"><article v-for="event in group.events" :key="`${event.instance}:${event.date}:${event.title}:${event.subtitle}`" class="calendar-event" :class="{ interactive: event.library_item_id || event.request_id }" @click="openDetail(event)"><img v-if="event.poster_url" :src="event.poster_url" alt=""><div><strong>{{ event.title }}</strong><span><span v-if="formatTime(event.date)" class="time-text">{{ formatTime(event.date) }} · </span>{{ event.subtitle }} · {{ event.instance }}</span></div><span class="badge" :class="event.has_file?'available':event.tracked?'pending':''">{{ event.has_file?'Disponible':event.tracked?'Suivi':'Catalogue' }}</span></article></div></section><p v-if="!loading&&!grouped.length" class="empty">Aucune sortie sur cette periode.</p><MediaDetailDrawer v-if="selected" :item="selected" :mode="selected._kind==='request'?'request':'library'" @close="selected=null" @updated="load"/></div></template>
<script setup>import { computed,onMounted,ref,nextTick } from 'vue';import { ChevronLeft,ChevronRight,RefreshCw } from '@lucide/vue';import { api } from '@/api';import MediaDetailDrawer from '@/components/MediaDetailDrawer.vue';const events=ref([]),search=ref(''),type=ref(''),tracked=ref(false),loading=ref(false),error=ref(''),cursor=ref(new Date()),selected=ref(null);const todayStr=localIso(new Date());const bounds=computed(()=>{const y=cursor.value.getFullYear(),m=cursor.value.getMonth();return {start:new Date(y,m,1),end:new Date(y,m+1,1)}});const periodLabel=computed(()=>new Intl.DateTimeFormat('fr-FR',{month:'long',year:'numeric'}).format(cursor.value));const filtered=computed(()=>events.value.filter(e=>(!search.value||e.title.toLowerCase().includes(search.value.toLowerCase()))&&(!type.value||e.type===type.value)));const grouped=computed(()=>{const map=new Map();filtered.value.forEach(e=>{const key=e.date.slice(0,10);if(!map.has(key))map.set(key,[]);map.get(key).push(e)});return [...map].map(([date,items])=>({date,events:items}))});function localIso(d){return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`}function longDate(v){return new Intl.DateTimeFormat('fr-FR',{weekday:'long',day:'numeric',month:'long'}).format(new Date(`${v}T12:00:00`))}function formatTime(v){if(!v)return '';const d=new Date(v);if(isNaN(d.getTime()))return '';if(v.endsWith('T00:00:00Z')||v.endsWith('T00:00:00.000Z'))return '';return d.toLocaleTimeString('fr-FR',{hour:'2-digit',minute:'2-digit'})}function openDetail(event){if(event.library_item_id){selected.value={id:event.library_item_id,_kind:'library'}}else if(event.request_id){selected.value={id:event.request_id,_kind:'request'}}}async function load(){loading.value=true;error.value='';try{events.value=await api(`/api/calendar?start=${localIso(bounds.value.start)}&end=${localIso(bounds.value.end)}&tracked_only=${tracked.value}`);nextTick(()=>{setTimeout(()=>{let el=document.getElementById(`date-${todayStr}`);if(!el){const upcomingGroup=grouped.value.find(g=>g.date>=todayStr);if(upcomingGroup)el=document.getElementById(`date-${upcomingGroup.date}`)}if(el)el.scrollIntoView({behavior:'smooth',block:'start'})},100)})}catch(e){error.value=e.message}finally{loading.value=false}}function move(delta){cursor.value=new Date(cursor.value.getFullYear(),cursor.value.getMonth()+delta,1);load()}function today(){cursor.value=new Date();load()}onMounted(load);</script>
